const DASHBOARD_BUTTON_STYLE=document.createElement('style');DASHBOARD_BUTTON_STYLE.textContent='.dash-card-button{width:100%;text-align:left;cursor:pointer;font:inherit;color:inherit}.dash-card-button:hover,.dash-card-button:focus-visible{border-color:var(--primary);box-shadow:0 0 0 4px color-mix(in srgb,var(--primary) 15%,transparent);outline:0}.dashboard-issue-header{display:flex;align-items:center;justify-content:space-between;gap:12px;flex-wrap:wrap}.dashboard-issue-header h3{margin:0}.order-tools{display:flex;gap:6px;flex-wrap:wrap;margin-top:8px}.order-tools .btn{padding:6px 10px;font-size:12px;min-height:0}';document.head.appendChild(DASHBOARD_BUTTON_STYLE);
async function boot(){const r=await fetch('/api/me',{cache:'no-store'});const d=await r.json().catch(()=>({authenticated:false}));if(!d.authenticated){location.href='/login.html?return='+encodeURIComponent(location.pathname);return}ME=d.user;if(!ADMIN_ROLES.includes(ME.role)){deniedPanel.classList.remove('hidden');return}adminApp.classList.remove('hidden');adminUserLabel.textContent=`${ME.displayName} (${ME.role})`;await loadData()}
async function loadData(){const calls=[fetch('/api/sops?admin=1',{cache:'no-store'}),fetch('/api/change-requests',{cache:'no-store'}),fetch('/api/support-requests',{cache:'no-store'}),fetch('/api/portal-settings',{cache:'no-store'}),fetch('/api/generator-history',{cache:'no-store'})];if(ME.role==='Admin')calls.push(fetch('/api/users',{cache:'no-store'}));const out=await Promise.all(calls);DATA=await out[0].json();SAVED_DATA=JSON.parse(JSON.stringify(DATA));REQUESTS=out[1].ok?await out[1].json():[];SUPPORTS=out[2].ok?await out[2].json():[];PORTAL=out[3].ok?await out[3].json():{staffLoginRequired:true};GEN_HISTORY=out[4].ok?await out[4].json():[];USERS=out[5]?.ok?await out[5].json():[];DATA.sops.forEach(s=>{if(!Array.isArray(s.attachments))s.attachments=[];if(!Array.isArray(s.versions))s.versions=[];if(!s.status)s.status='Draft'});currentSopId=currentSopId||DATA.sops[0]?.id;currentSectionId=currentSectionId||DATA.sections[0]?.id;fillBrand();renderAll();syncJson();applyRoleUi()}
