function normalizeHex(v,fallback){v=String(v||'').trim();return /^#[0-9a-fA-F]{6}$/.test(v)?v:fallback}function setPortalTheme(brand){if(window.applyPortalBrand)return window.applyPortalBrand(brand);for(const[k,v]of Object.entries({primary:brand.primaryColor,accent:brand.accentColor,dark:brand.darkColor,light:brand.lightColor}))document.documentElement.style.setProperty('--'+k,v)}
function fillBrand(){DATA.brand=DATA.brand||{};const portalName=DATA.brand.name||'SOP Portal',companyName=DATA.brand.company||'';const defaultHeadline=`${companyName||portalName} SOPs in one searchable place.`,savedHeadline=String(DATA.brand.staffHeaderTitle||'').trim();brand_name.value=DATA.brand.name||'';if(byId('brand_company'))brand_company.value=companyName;if(byId('brand_staffHeaderTitle'))brand_staffHeaderTitle.value=savedHeadline||defaultHeadline;if(byId('brand_staffRules'))brand_staffRules.value=(Array.isArray(DATA.brand.staffRules)?DATA.brand.staffRules:['Use approved SOPs only.','Protect client privacy and sensitive data.','Suggest a change if something is outdated.']).join('\n');document.title=`Admin - ${portalName}`;if(byId('adminPortalLabel'))adminPortalLabel.textContent=portalName;if(byId('brand_vertical'))brand_vertical.value=DATA.brand.vertical||DATA.brand.subtitle||'';if(byId('brand_website'))brand_website.value=DATA.brand.website||'';if(byId('config_port'))config_port.value=PORTAL.port||8086;if(byId('config_mobileBaseUrl')){config_mobileBaseUrl.value=PORTAL.mobileBaseUrl||'';const sample=(PORTAL.lanUrls||[])[0];if(byId('mobileBaseUrlHelp'))mobileBaseUrlHelp.textContent=sample?`Use the local network URL phones can reach. Suggested: ${sample}`:'Use the local network URL phones can reach. Leave blank to use the current browser URL.'}brand_subtitle.value=DATA.brand.subtitle||'';brand_tagline.value=DATA.brand.tagline||'';brand_primaryColor.value=normalizeHex(DATA.brand.primaryColor,'#19aeb6');brand_accentColor.value=normalizeHex(DATA.brand.accentColor,'#d8df62');brand_darkColor.value=normalizeHex(DATA.brand.darkColor,'#07151a');brand_lightColor.value=normalizeHex(DATA.brand.lightColor,'#f6fbfb');renderDefaultOwnerSelect();set_reviewCadence.value=DATA.settings.reviewCadence||'';renderBrandLogoPreview();setPortalTheme(DATA.brand)}
function ensureDefaultOwnerSelect(){const el=byId('set_defaultOwner');if(!el||el.tagName==='SELECT')return el;const sel=document.createElement('select');sel.id=el.id;sel.className=el.className;sel.value=el.value||'';el.replaceWith(sel);sel.addEventListener('input',collectBrand);return sel}function renderDefaultOwnerSelect(){const el=ensureDefaultOwnerSelect();if(!el)return;const current=(DATA&&DATA.settings&&DATA.settings.defaultOwner)||el.value||'';const seen=new Set(),options=[''];(USERS||[]).filter(u=>u&&u.active!==false).forEach(u=>{const value=String(u.displayName||u.username||'').trim();if(!value)return;const key=value.toLowerCase();if(seen.has(key))return;seen.add(key);options.push(value)});if(current&&!seen.has(String(current).toLowerCase()))options.push(current);el.innerHTML=options.map(value=>`<option value="${escAttr(value)}" ${value===current?'selected':''}>${value?esc(value):'No default owner'}</option>`).join('');el.value=current}
function collectBrand(){DATA.brand=DATA.brand||{};DATA.brand.name=brand_name.value.trim()||'SOP Portal';if(byId('brand_company'))DATA.brand.company=brand_company.value.trim();delete DATA.brand.adminTitle;delete DATA.brand.loginTitle;delete DATA.brand.loginLabel;delete DATA.brand.supportTitle;delete DATA.brand.supportSubject;delete DATA.brand.staffHeaderLabel;if(byId('brand_staffHeaderTitle'))DATA.brand.staffHeaderTitle=brand_staffHeaderTitle.value.trim()||`${DATA.brand.company||DATA.brand.name||'SOP Portal'} SOPs in one searchable place.`;if(byId('brand_staffRules'))DATA.brand.staffRules=brand_staffRules.value.split(/\r?\n/).map(x=>x.trim()).filter(Boolean);document.title=`Admin - ${DATA.brand.name}`;if(byId('adminPortalLabel'))adminPortalLabel.textContent=DATA.brand.name;if(byId('brand_vertical'))DATA.brand.vertical=brand_vertical.value;if(byId('brand_website'))DATA.brand.website=brand_website.value;DATA.brand.subtitle=brand_subtitle.value;DATA.brand.tagline=brand_tagline.value;DATA.brand.primaryColor=normalizeHex(brand_primaryColor.value,'#19aeb6');DATA.brand.accentColor=normalizeHex(brand_accentColor.value,'#d8df62');DATA.brand.darkColor=normalizeHex(brand_darkColor.value,'#07151a');DATA.brand.lightColor=normalizeHex(brand_lightColor.value,'#f6fbfb');if(!DATA.brand.logoUrl)DATA.brand.logoUrl='/portal-logo.png';const ownerSelect=ensureDefaultOwnerSelect();DATA.settings.defaultOwner=ownerSelect?ownerSelect.value:'';DATA.settings.reviewCadence=set_reviewCadence.value;setPortalTheme(DATA.brand);renderBrandLogoPreview();syncJson()}
function cleanMobileBaseUrl(value){value=String(value||'').trim().replace(/\/+$/,'');if(!value)return'';value=value.replace(/^(https?:\/\/\d{1,3}(?:\.\d{1,3}){3})\.(\d{2,5})$/,'$1:$2');try{const u=new URL(value);return/^https?:$/.test(u.protocol)?u.origin:''}catch(e){return''}}
function renderBrandLogoPreview(){const img=byId('brandLogoPreview');if(img)img.src=(DATA.brand&&DATA.brand.logoUrl)||'/portal-logo.png'}async function uploadBrandLogo(){const input=byId('brandLogoFile');const file=input&&input.files&&input.files[0];if(!file)return alert('Choose a logo file first.');if(!file.type.startsWith('image/')&&!/\.(png|jpe?g|gif|webp|avif|svg)$/i.test(file.name))return alert('Logo must be an image file.');if(file.size>5*1024*1024)return alert('Logo must be 5 MB or smaller.');const dataUrl=await fileToDataUrl(file);const r=await fetch('/api/brand-logo',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({name:file.name,type:file.type,dataUrl})});const d=await r.json().catch(()=>({}));if(!r.ok)return alert(d.error||'Logo upload failed');DATA.brand=DATA.brand||{};DATA.brand.logoUrl=d.brand.logoUrl;if(d.dataVersion)DATA._dataVersion=d.dataVersion;input.value='';fillBrand();syncJson();status.textContent='Logo uploaded and saved.'}async function resetBrandLogo(){if(!confirm('Reset customer logo to the default portal logo?'))return;const r=await fetch('/api/brand-logo',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({reset:true})});const d=await r.json().catch(()=>({}));if(!r.ok)return alert(d.error||'Logo reset failed');DATA.brand=DATA.brand||{};DATA.brand.logoUrl=d.brand.logoUrl||'/portal-logo.png';if(d.dataVersion)DATA._dataVersion=d.dataVersion;fillBrand();syncJson();status.textContent='Logo reset to default.'}
function currentColorValues(){return{primaryColor:normalizeHex(brand_primaryColor.value,'#19aeb6'),accentColor:normalizeHex(brand_accentColor.value,'#d8df62'),darkColor:normalizeHex(brand_darkColor.value,'#07151a'),lightColor:normalizeHex(brand_lightColor.value,'#f6fbfb')}}function renderBrandColorStatus(msg){const el=byId('brandColorStatus');if(el)el.textContent=msg||''}async function brandColorAction(action){let promptText='';if(action==='revert-previous')promptText='Revert to the last published color scheme?';if(action==='restore-default')promptText='Restore this portal to the saved default colors?';if(action==='save-default')promptText='Save the current colors as the new default colors?';if(promptText&&!confirm(promptText))return;collectBrand();const r=await fetch('/api/brand-colors',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action,colors:currentColorValues()})});const d=await r.json().catch(()=>({}));if(!r.ok)return alert(d.error||'Color action failed');if(d.brand){DATA.brand=Object.assign(DATA.brand||{},d.brand);if(d.dataVersion)DATA._dataVersion=d.dataVersion;fillBrand();setPortalTheme(DATA.brand)}if(action==='save-default')renderBrandColorStatus('Current colors saved as the new default color scheme and applied to the portal.');if(action==='restore-default')renderBrandColorStatus('Default colors restored and saved. Refresh the staff portal to confirm.');if(action==='revert-previous')renderBrandColorStatus('Last color scheme restored and saved. Refresh the staff portal to confirm.');syncJson()}
function setHelpScreenshotStatus(msg){const el=byId('helpScreenshotStatus');if(el)el.textContent=msg||''}async function recaptureHelpScreenshots(){if(ME?.role!=='Admin')return alert('Admin role required.');if(!confirm('Save current Brand / Settings, then replace all Help screenshots with current branded screenshots?'))return;const btn=byId('recaptureHelpScreenshotsBtn');if(btn)btn.disabled=true;try{setHelpScreenshotStatus('Saving current portal settings before screenshot capture...');const saved=await publish();if(saved===false)return;setHelpScreenshotStatus('Capturing Help screenshots with the browser. This may take a minute...');const r=await fetch('/api/help-screenshots/recapture',{method:'POST',headers:{'Content-Type':'application/json'},body:'{}'}),d=await r.json().catch(()=>({}));if(!r.ok){const detail=String(d.details||'').trim().split(/\r?\n/).filter(Boolean).slice(-4).join('\n');throw new Error((d.error||'Help screenshot capture failed.')+(detail?'\n\nDetails:\n'+detail:''))}setHelpScreenshotStatus(`Help screenshots refreshed at ${new Date().toLocaleString()}. Open Help and refresh the browser if an old image is cached.`);status.textContent=`Help screenshots recaptured and saved (${d.count||0} images).`}catch(e){setHelpScreenshotStatus(e.message||'Help screenshot capture failed.');alert(e.message||'Help screenshot capture failed.')}finally{if(btn)btn.disabled=false}}document.addEventListener('click',e=>{if(e.target&&e.target.id==='recaptureHelpScreenshotsBtn')recaptureHelpScreenshots()});
function currentSop(){return DATA?.sops.find(x=>x.id===currentSopId)}function uniqueSopId(base){let id=base,n=2;while(DATA.sops.some(s=>s.id===id))id=base+'-'+n++;return id}function makeDraftCopyIfNeeded(targetStatus){const s=currentSop(),saved=SAVED_DATA?.sops?.find(x=>x.id===currentSopId);if(!s||!saved||saved.status!=='Approved'||s.draftOf||!['Draft','Pending Review'].includes(targetStatus))return;const draft=JSON.parse(JSON.stringify(s));draft.id=uniqueSopId(saved.id+'-DRAFT');draft.draftOf=saved.id;draft.status=targetStatus;draft.versions=[];const idx=DATA.sops.findIndex(x=>x.id===saved.id);if(idx>-1)DATA.sops[idx]=JSON.parse(JSON.stringify(saved));DATA.sops.push(draft);currentSopId=draft.id;renderSopList();renderSopForm()}function daysUntil(date){const t=Date.parse(date);if(!t)return 9999;return Math.ceil((t-Date.now())/86400000)}function actionNeeded(){const today=new Date();today.setHours(0,0,0,0);return DATA.sops.map(s=>{let issues=[];if(s.status==='Draft')issues.push('draft');if(s.status==='Pending Review')issues.push('pending approval');if(s.status==='Rejected')issues.push('rejected');if(s.nextReview){const d=daysUntil(s.nextReview);if(new Date(s.nextReview)<today)issues.push('review overdue');else if(d<=30)issues.push('review due soon')}return{s,issues}}).filter(x=>x.issues.length)}
function dashboardCard(label,value,target){return`<button type="button" class="dash-card dash-card-button ${currentDashboardFilter===target?'active':''}" onclick="openDashboardCard('${escAttr(target)}')" aria-label="Open ${escAttr(label)}"><strong>${value}</strong><span>${esc(label)}</span></button>`}function openDashboardCard(target){if(target==='sops'||target==='approved'){currentDashboardFilter='';setTab('sops');if(byId('adminSearch'))adminSearch.value='';if(byId('adminSectionFilter'))adminSectionFilter.value='';if(byId('adminStatusFilter')){adminStatusFilter.value=target==='approved'?'Approved':'';renderSopList()}return}if(target==='users'){currentDashboardFilter='';setTab('users');return}currentDashboardFilter=target;setTab('dashboard');dashboardIssues?.scrollIntoView({behavior:'smooth',block:'start'})}function renderDashboard(){const s=DATA.sops,open=REQUESTS.filter(r=>r.status==='Open').length;dashboardCards.innerHTML=[dashboardCard('Total SOPs',s.length,'sops'),dashboardCard('Approved',s.filter(x=>x.status==='Approved').length,'approved'),dashboardCard('Pending',s.filter(x=>x.status==='Pending Review').length,'pending'),dashboardCard('Drafts',s.filter(x=>x.status==='Draft').length,'drafts'),dashboardCard('Overdue',s.filter(x=>x.nextReview&&daysUntil(x.nextReview)<0).length,'overdue'),dashboardCard('Change Requests',open,'requests'),dashboardCard('Staff login',PORTAL.staffLoginRequired?'On':'Off','users'),dashboardCard('Users',USERS.length||'-','users')].join('');const allIssues=actionNeeded();let heading='Action Needed',body='';if(currentDashboardFilter==='pending'){const issues=allIssues.filter(x=>x.s.status==='Pending Review');body=issues.length?issues.slice(0,80).map(x=>`<div class="issue"><div><b>${esc(x.s.id)} - ${esc(x.s.title)}</b><div class="small">${esc(x.issues.join(', '))}</div></div><button class="btn secondary" onclick="editSop('${escAttr(x.s.id)}')">Edit</button></div>`).join(''):'<p class="small">No pending SOPs found.</p>';heading='Pending SOPs'}else if(currentDashboardFilter==='drafts'){const issues=allIssues.filter(x=>x.s.status==='Draft');body=issues.length?issues.slice(0,80).map(x=>`<div class="issue"><div><b>${esc(x.s.id)} - ${esc(x.s.title)}</b><div class="small">${esc(x.issues.join(', '))}</div></div><button class="btn secondary" onclick="editSop('${escAttr(x.s.id)}')">Edit</button></div>`).join(''):'<p class="small">No draft SOPs found.</p>';heading='Draft SOPs'}else if(currentDashboardFilter==='overdue'){const issues=allIssues.filter(x=>x.s.nextReview&&daysUntil(x.s.nextReview)<0);body=issues.length?issues.slice(0,80).map(x=>`<div class="issue"><div><b>${esc(x.s.id)} - ${esc(x.s.title)}</b><div class="small">${esc(x.issues.join(', '))}</div></div><button class="btn secondary" onclick="editSop('${escAttr(x.s.id)}')">Edit</button></div>`).join(''):'<p class="small">No overdue reviews found.</p>';heading='Overdue Reviews'}else if(currentDashboardFilter==='requests'){const req=REQUESTS.filter(r=>r.status==='Open');body=req.length?req.slice(0,80).map(r=>`<div class="issue"><div><b>${esc(r.sopId)} - ${esc(r.sopTitle)}</b><div class="small">${esc(r.urgency)} · ${esc(r.requester)} · ${esc(r.issue)}</div></div><button class="btn secondary" onclick="setTab('requests');selectRequest('${escAttr(r.id)}')">Review</button></div>`).join(''):'<p class="small">No open change requests found.</p>';heading='Open Change Requests'}else{const req=REQUESTS.filter(r=>r.status==='Open'),requestRows=req.slice(0,80).map(r=>`<div class="issue"><div><b>Change Request: ${esc(r.sopId)} - ${esc(r.sopTitle)}</b><div class="small">${esc(r.urgency)} &middot; ${esc(r.requester)} &middot; ${esc(r.issue)}</div></div><button class="btn secondary" onclick="setTab('requests');selectRequest('${escAttr(r.id)}')">Review</button></div>`),sopRows=allIssues.slice(0,Math.max(0,80-requestRows.length)).map(x=>`<div class="issue"><div><b>${esc(x.s.id)} - ${esc(x.s.title)}</b><div class="small">${esc(x.issues.join(', '))}</div></div><button class="btn secondary" onclick="editSop('${escAttr(x.s.id)}')">Edit</button></div>`);body=requestRows.length||sopRows.length?[...requestRows,...sopRows].join(''):'<p class="small">No open change requests, draft, pending, rejected, overdue, or due-soon SOPs found.</p>'}const clear=currentDashboardFilter?`<button type="button" class="btn secondary" onclick="currentDashboardFilter='';renderDashboard()">Show All</button>`:'';dashboardIssues.innerHTML=`<div class="dashboard-issue-header"><h3>${esc(heading)}</h3>${clear}</div>${body}`}
function editSop(id){currentSopId=id;setTab('sops');renderSopList();renderSopForm()}function renderSopList(){const q=norm(adminSearch.value),section=byId('adminSectionFilter')?.value||'',status=byId('adminStatusFilter')?.value||'';const list=DATA.sops.filter(s=>(!section||s.sectionId===section)&&(!status||s.status===status)&&(!q||norm([s.id,s.title,s.tags,s.sectionId,s.status,sectionTitle(s.sectionId)].join(' ')).includes(q)));if(byId('sopListCount'))sopListCount.textContent=`Showing ${list.length} of ${DATA.sops.length} SOP${DATA.sops.length===1?'':'s'}.`;sopAdminList.innerHTML=list.length?list.map(s=>`<div class="sop-admin-item ${s.id===currentSopId?'active':''}" onclick="selectSop('${escAttr(s.id)}')"><b>${esc(s.id)}</b> <span class="pill ${statusClass(s.status)}">${esc(s.status)}</span><br>${esc(s.title)}<div class="small">${esc(sectionTitle(s.sectionId))}</div><div class="order-tools"><button type="button" class="btn secondary" onclick="moveSopInSection('${escAttr(s.id)}',-1,event)">Move Up</button><button type="button" class="btn secondary" onclick="moveSopInSection('${escAttr(s.id)}',1,event)">Move Down</button></div></div>`).join(''):'<p class="small">No SOPs match the current filters.</p>'}function selectSop(id){if(saveSop(false)===false)return;currentSopId=id;selectedVersionId=null;renderSopList();renderSopForm()}
function renderSectionOptions(){sop_sectionId.innerHTML=DATA.sections.map(s=>`<option value="${escAttr(s.id)}">${esc(s.title)}</option>`).join('');if(byId('adminSectionFilter')){const current=adminSectionFilter.value;adminSectionFilter.innerHTML='<option value="">All Sections</option>'+DATA.sections.map(s=>`<option value="${escAttr(s.id)}">${esc(s.title)}</option>`).join('');adminSectionFilter.value=[...adminSectionFilter.options].some(o=>o.value===current)?current:''}}function renderStatusOptions(value){const opts=ME.role==='Editor'?['Draft','Pending Review']:['Draft','Pending Review','Approved','Rejected','Archived'];sop_status.innerHTML=opts.map(x=>`<option>${esc(x)}</option>`).join('');sop_status.value=opts.includes(value)?value:opts[0]}function renderSopForm(){const s=currentSop();if(!s)return;sopForm.dataset.sopId=s.id;sop_id.value=s.id;renderStatusOptions(s.status);sop_sectionId.value=s.sectionId;sop_version.value=s.version;sop_title.value=s.title;sop_purpose.value=s.purpose;sop_scope.value=s.scope;sop_prerequisites.value=s.prerequisites;sop_steps.value=(s.steps||[]).join('\n');sop_validation.value=s.validation;sop_exceptions.value=s.exceptions;sop_owner.value=s.owner;sop_roles.value=s.roles;sop_lastUpdated.value=s.lastUpdated;sop_nextReview.value=s.nextReview;sop_tags.value=s.tags;exportCurrentPdfLink.href='/api/export-pdf?sopId='+encodeURIComponent(s.id);renderAttachmentsAdmin();renderVersions()}
function saveSop(record=false,action='Edit'){const s=currentSop();if(!s)return true;if(sopForm.dataset.sopId&&sopForm.dataset.sopId!==s.id){alert('The selected SOP changed before this save completed. Please reselect the SOP and try again.');return false}const old=s.id;s.id=sop_id.value.trim()||old;s.status=sop_status.value;s.sectionId=sop_sectionId.value;s.version=sop_version.value;s.title=sop_title.value;s.purpose=sop_purpose.value;s.scope=sop_scope.value;s.prerequisites=sop_prerequisites.value;s.steps=sop_steps.value.split('\n').map(x=>x.trim()).filter(Boolean);s.validation=sop_validation.value;s.exceptions=sop_exceptions.value;s.owner=sop_owner.value;s.roles=sop_roles.value;s.lastUpdated=sop_lastUpdated.value;s.nextReview=sop_nextReview.value;s.tags=sop_tags.value;currentSopId=s.id;sopForm.dataset.sopId=s.id;if(record)recordVersion(s,action,versionSummary.value||action);syncJson();renderSopList();renderDashboard();renderVersions();exportCurrentPdfLink.href='/api/export-pdf?sopId='+encodeURIComponent(s.id);return true}
function recordVersion(s,action,summary){const snap=JSON.parse(JSON.stringify({...s,versions:undefined}));s.versions=s.versions||[];s.versions.unshift({id:'v-'+Date.now(),timestamp:new Date().toISOString(),editor:ME.username,action,status:s.status,summary,snapshot:snap});s.version=incrementVersion(s.version);s.lastUpdated=new Date().toISOString().slice(0,10)}function approvalReadyFromForm(){return sop_title.value.trim()&&sop_steps.value.split('\n').some(x=>x.trim())}function approveDraftIntoOriginal(){const draft=currentSop();if(!draft?.draftOf)return;const originalId=draft.draftOf,idx=DATA.sops.findIndex(x=>x.id===originalId),draftIdx=DATA.sops.findIndex(x=>x.id===draft.id),merged=JSON.parse(JSON.stringify(draft));merged.id=originalId;delete merged.draftOf;merged.status='Approved';if(idx>-1)DATA.sops[idx]=merged;else DATA.sops.push(merged);if(draftIdx>-1)DATA.sops.splice(draftIdx,1);currentSopId=originalId}function setWorkflowButtons(disabled){[publishBtn,saveDraftBtn,submitReviewBtn,approveBtn,rejectBtn,archiveBtn].forEach(b=>{if(b)b.disabled=disabled})}async function setStatus(st,action){if(!MANAGER_ROLES.includes(ME.role))return alert('Manager/Admin required.');if(st==='Approved'&&!approvalReadyFromForm())return alert('Approval requires an SOP title and at least one step.');if(savingAdmin)return;savingAdmin=true;setWorkflowButtons(true);try{sop_status.value=st;if(st==='Approved'&&!sop_nextReview.value){const d=new Date();d.setMonth(d.getMonth()+3);sop_nextReview.value=d.toISOString().slice(0,10)}if(saveSop(true,action)===false)return;if(st==='Approved')approveDraftIntoOriginal();await publish()}finally{savingAdmin=false;setWorkflowButtons(false)}}
function addSop(){if(saveSop(false)===false)return;const s={id:'NEW-'+String(DATA.sops.length+1).padStart(3,'0'),sectionId:DATA.sections[0].id,status:'Draft',title:'New SOP',purpose:'Describe purpose.',scope:'Describe scope.',owner:DATA.settings.defaultOwner,roles:'All Staff, Manager',version:'0.1',lastUpdated:new Date().toISOString().slice(0,10),nextReview:'',prerequisites:'List prerequisites.',steps:['Step one','Step two'],validation:'Describe done state.',exceptions:'List exceptions.',tags:'',attachments:[],versions:[]};DATA.sops.push(s);currentSopId=s.id;recordVersion(s,'Created','New SOP created.');renderAll();syncJson()}function duplicateSop(){if(saveSop(false)===false)return;const s=currentSop();if(!s)return;const c=JSON.parse(JSON.stringify(s));c.id=s.id+'-COPY';c.title=s.title+' Copy';c.status='Draft';c.attachments=[];c.versions=[];DATA.sops.push(c);currentSopId=c.id;recordVersion(c,'Duplicated','Duplicated SOP.');renderAll();syncJson()}function deleteSop(){if(!MANAGER_ROLES.includes(ME.role))return alert('Manager/Admin required.');const i=DATA.sops.findIndex(x=>x.id===currentSopId);if(i<0)return;if(!confirm('Delete this SOP?'))return;DATA.sops.splice(i,1);currentSopId=DATA.sops[0]?.id;renderAll();syncJson()}
function renderSectionList(){sectionList.innerHTML=DATA.sections.map(s=>`<div class="section-row ${s.id===currentSectionId?'active':''}" onclick="selectSection('${escAttr(s.id)}')"><b>${esc(s.icon||'📋')} ${esc(s.title)}</b><div class="small">${esc(s.id)}</div><div class="order-tools"><button type="button" class="btn secondary" onclick="moveSection('${escAttr(s.id)}',-1,event)">Move Up</button><button type="button" class="btn secondary" onclick="moveSection('${escAttr(s.id)}',1,event)">Move Down</button></div></div>`).join('')}function selectSection(id){saveSectionForm();currentSectionId=id;renderSectionList();renderSectionForm()}function renderSectionForm(){const s=DATA.sections.find(x=>x.id===currentSectionId);if(!s)return;sec_id.value=s.id;if(s.icon&&![...sec_icon.options].some(o=>o.value===s.icon))sec_icon.insertAdjacentHTML('beforeend',`<option value="${escAttr(s.icon)}">${esc(s.icon)} Custom</option>`);sec_icon.value=s.icon||'📋';sec_title.value=s.title;sec_description.value=s.description}function saveSectionForm(){if(!MANAGER_ROLES.includes(ME.role))return;const s=DATA?.sections.find(x=>x.id===currentSectionId);if(!s)return;const old=s.id;s.id=sec_id.value.trim()||old;s.icon=sec_icon.value;s.title=sec_title.value;s.description=sec_description.value;DATA.sops.forEach(x=>{if(x.sectionId===old)x.sectionId=s.id});currentSectionId=s.id;renderSectionOptions();syncJson()}function moveSection(id,dir,event){event?.stopPropagation();if(!MANAGER_ROLES.includes(ME.role))return alert('Manager/Admin required.');saveSectionForm();const i=DATA.sections.findIndex(x=>x.id===id),j=i+dir;if(i<0||j<0||j>=DATA.sections.length)return;[DATA.sections[i],DATA.sections[j]]=[DATA.sections[j],DATA.sections[i]];currentSectionId=id;renderAll();syncJson();status.textContent='Section order updated. Use Save All Changes to publish.'}function moveSopInSection(id,dir,event){event?.stopPropagation();if(!MANAGER_ROLES.includes(ME.role))return alert('Manager/Admin required.');if(saveSop(false)===false)return;const sop=DATA.sops.find(x=>x.id===id);if(!sop)return;const peers=DATA.sops.map((s,i)=>({s,i})).filter(x=>x.s.sectionId===sop.sectionId),pos=peers.findIndex(x=>x.s.id===id),target=peers[pos+dir];if(pos<0||!target)return;const i=peers[pos].i,j=target.i;[DATA.sops[i],DATA.sops[j]]=[DATA.sops[j],DATA.sops[i]];currentSopId=id;currentSectionId=sop.sectionId;renderAll();syncJson();status.textContent='SOP order updated. Use Save All Changes to publish.'}function addSection(){if(!MANAGER_ROLES.includes(ME.role))return alert('Manager/Admin required.');saveSectionForm();const id='section-'+(DATA.sections.length+1);const s={id,title:'New Section',description:'Describe this section.',icon:'📋'};DATA.sections.push(s);currentSectionId=id;renderSectionList();renderSectionForm();renderSectionOptions();syncJson()}function deleteSection(){if(!MANAGER_ROLES.includes(ME.role))return alert('Manager/Admin required.');const idx=DATA.sections.findIndex(x=>x.id===currentSectionId);if(idx<0)return;if(DATA.sops.some(s=>s.sectionId===currentSectionId))return alert('Move or delete SOPs in this section first.');if(!confirm('Delete this section?'))return;DATA.sections.splice(idx,1);currentSectionId=DATA.sections[0]?.id;renderSectionList();renderSectionForm();renderSectionOptions();syncJson()}
function renderAttachmentsAdmin(){const s=currentSop(),files=s?.attachments||[];attachmentAdminList.innerHTML=files.length?files.map(a=>`<div class="attachment-admin-item"><div>${isImage(a)?`<img src="${escAttr(a.url)}" alt="">`:'📎'}</div><div><b>${esc(a.name)}</b><br><span class="small">${esc(a.type||'file')} · ${formatBytes(a.size)} · ${esc(a.uploadedBy||'')}</span><br><a href="${escAttr(a.url)}" ${isImage(a)?'target="_blank"':'download'}>${isImage(a)?'Open full size':'Download'}</a></div><button type="button" class="btn danger" onclick="deleteAttachment('${escAttr(a.id)}')">Delete</button></div>`).join(''):'<p class="small">No files attached.</p>'}async function uploadAttachments(){if(saveSop(false)===false)return;let s=currentSop(),files=[...attachmentFiles.files];if(!files.length)return alert('Choose files first.');if(!confirm('Save current SOP changes before uploading?'))return;if(ME.role==='Editor')makeDraftCopyIfNeeded('Draft');const saved=await publish();if(saved===false)return;s=currentSop();for(const file of files){if(file.size>10*1024*1024){alert(file.name+' skipped: over 10 MB');continue}const dataUrl=await fileToDataUrl(file);const r=await fetch('/api/upload',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({sopId:s.id,name:file.name,type:file.type,dataUrl})});const d=await r.json().catch(()=>({}));if(!r.ok){alert(d.error||'Upload failed');continue}s.attachments=s.attachments||[];s.attachments.push(d.attachment);if(d.dataVersion)DATA._dataVersion=d.dataVersion}attachmentFiles.value='';SAVED_DATA=JSON.parse(JSON.stringify(DATA));renderAll();syncJson()}async function deleteAttachment(id){const s=currentSop();if(!confirm('Delete this attachment?'))return;const r=await fetch('/api/delete-attachment',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({sopId:s.id,attachmentId:id})});const d=await r.json().catch(()=>({}));if(!r.ok)return alert(d.error||'Delete failed');DATA=d.sops;SAVED_DATA=JSON.parse(JSON.stringify(DATA));renderAll();syncJson()}
function renderVersions(){const s=currentSop(),v=s?.versions||[];versionList.innerHTML=v.length?v.map(x=>`<div class="version-row ${x.id===selectedVersionId?'active':''}" onclick="selectVersion('${escAttr(x.id)}')"><b>${esc(x.action)}</b> <span class="pill ${statusClass(x.status)}">${esc(x.status)}</span><div class="small">${esc(new Date(x.timestamp).toLocaleString())} · ${esc(x.editor||'')} · ${esc(x.summary||'')}</div></div>`).join(''):'<p class="small">No version history.</p>'}function selectVersion(id){selectedVersionId=id;renderVersions()}function rollbackVersion(){const s=currentSop(),v=(s?.versions||[]).find(x=>x.id===selectedVersionId);if(!v)return alert('Select a version first.');if(!confirm('Rollback to selected version?'))return;const keep=s.versions;Object.assign(s,JSON.parse(JSON.stringify(v.snapshot)));s.versions=keep;s.status='Draft';recordVersion(s,'Rollback','Rolled back to previous version.');renderAll();syncJson()}
function renderRequests(){const f=requestFilter.value||'All';const list=REQUESTS.filter(r=>f==='All'||r.status===f);requestList.innerHTML=list.length?list.map(r=>`<div class="request-row ${r.id===currentRequestId?'active':''}" onclick="selectRequest('${escAttr(r.id)}')"><b>${esc(r.sopId)} - ${esc(r.sopTitle)}</b><div class="small">${esc(r.status)} · ${esc(r.urgency)} · ${esc(r.requester)}</div></div>`).join(''):'<p class="small">No requests.</p>';renderRequestDetail()}function selectRequest(id){currentRequestId=id;renderRequests()}function renderRequestDetail(){const r=REQUESTS.find(x=>x.id===currentRequestId);if(!r){requestDetail.innerHTML='<p class="small">Select a request.</p>';return}requestDetail.innerHTML=`<h3>${esc(r.sopId)} - ${esc(r.sopTitle)}</h3><p><b>Status:</b> ${esc(r.status)} · <b>Urgency:</b> ${esc(r.urgency)} · <b>Requester:</b> ${esc(r.requester)}</p><h4>Issue</h4><p>${esc(r.issue)}</p><h4>Suggested change</h4><p>${esc(r.suggestedChange||'None')}</p><h4>Manager note</h4><textarea id="requestManagerNote">${esc(r.managerNote||'')}</textarea><div class="toolbar" style="margin-top:12px"><button class="btn warn" onclick="updateRequest('${escAttr(r.id)}','Approved')">Approve</button><button class="btn danger" onclick="updateRequest('${escAttr(r.id)}','Rejected')">Reject</button><button class="btn primary" onclick="updateRequest('${escAttr(r.id)}','Completed')">Complete</button><button class="btn secondary" onclick="editSop('${escAttr(r.sopId)}')">Open SOP</button></div>`}async function updateRequest(id,statusValue){const r=await fetch('/api/change-requests',{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({id,status:statusValue,managerNote:byId('requestManagerNote')?.value||''})});const d=await r.json().catch(()=>({}));if(!r.ok)return alert(d.error||'Update failed');REQUESTS=d.requests;currentRequestId=id;renderDashboard();renderRequests()}
function renderSupports(){supportList.innerHTML=SUPPORTS.length?SUPPORTS.map(s=>`<div class="support-row ${s.id===currentSupportId?'active':''}" onclick="selectSupport('${escAttr(s.id)}')"><b>${esc(s.subject)}</b><div class="small">${esc(s.urgency)} · ${esc(s.requester)} · ${esc((s.createdAt||'').slice(0,10))}</div></div>`).join(''):'<p class="small">No support requests saved locally.</p>';const clearBtn=byId('clearSupportRequestsBtn');if(clearBtn)clearBtn.disabled=!SUPPORTS.length;renderSupportDetail()}function selectSupport(id){currentSupportId=id;renderSupports()}function renderSupportDetail(){const s=SUPPORTS.find(x=>x.id===currentSupportId);if(!s){supportDetail.innerHTML='<p class="small">Select a support request.</p>';return}supportDetail.innerHTML=`<h3>${esc(s.subject)}</h3><p><b>Requester:</b> ${esc(s.requester)} (${esc(s.requesterUsername)})<br><b>Email:</b> ${esc(s.email)}<br><b>Phone:</b> ${esc(s.phone)}<br><b>Urgency:</b> ${esc(s.urgency)}<br><b>Page:</b> ${esc(s.page)}</p><h4>Message</h4><p>${esc(s.message)}</p><p class="small">This request was submitted through the portal support form and backed up locally.</p>`}async function clearSupportRequests(){if(ME?.role!=='Admin')return alert('Admin role required.');const count=SUPPORTS.length;if(!count)return alert('There are no support requests to clear.');if(!confirm(`Delete all ${count} locally saved portal support request${count===1?'':'s'}? This cannot be undone from this page.`))return;const r=await fetch('/api/support-requests/clear',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({confirm:'CLEAR'})});const d=await r.json().catch(()=>({}));if(!r.ok)return alert(d.error||'Could not clear support requests.');SUPPORTS=[];currentSupportId=null;renderSupports();status.textContent=`Cleared ${d.removed||count} support request${(d.removed||count)===1?'':'s'}. Backup created.`}
async function runSmokeTest(){if(ME.role!=='Admin')return alert('Admin role required.');smokeTestOutput.textContent='Running smoke test...';const r=await fetch('/api/smoke-test',{cache:'no-store'});const d=await r.json().catch(()=>({ok:false,error:'Smoke test response was not valid JSON'}));if(!r.ok){smokeTestOutput.textContent=d.error||'Smoke test failed to run.';return}smokeTestOutput.textContent=(d.ok?'PASS':'CHECK')+' - '+d.ranAt+'\n\n'+(d.checks||[]).map(x=>`${x.pass?'PASS':'FAIL'} ${x.name}${x.detail?' - '+x.detail:''}`).join('\n')}
function renderGenerator(){if(!byId('genExistingSection')||!DATA)return;genExistingSection.innerHTML=(DATA.sections||[]).map(s=>`<option value="${escAttr(s.id)}">${esc(s.title)}</option>`).join('');genExistingSection.disabled=genMode.value!=='one';if(!GEN_PREVIEW.sops.length)genPreview.innerHTML='<p class="small">No generated SOPs previewed yet.</p>';renderGeneratorHistory()}
function buildGeneratorPrompt(){const mode=genMode.value,count=Math.max(1,Math.min(40,Number(genCount.value)||1)),existing=DATA.sections.find(s=>s.id===genExistingSection.value);const modeText=mode==='one'?'Create exactly one SOP.':mode==='section'?`Create one new section named "${genSectionName.value||'Recommended Section'}" with about ${count} SOPs.`:`Create a starter portal set with useful sections and about ${count} SOPs total.`;const prompt=`You are helping create draft SOP content for a local SOP Portal. Return ONLY valid JSON. Do not include markdown outside the JSON.\n\nGoal: ${modeText}\nBusiness type: ${genVertical.value||'Not specified'}\nBusiness website or notes: ${genWebsite.value||'Not specified'}\nSoftware stack/tools: ${genSoftware.value||'Not specified'}\nIntended users: ${genAudience.value||'All staff'}\nRisk level: ${genRisk.value}\nPreferred style: ${genTone.value}\nExisting section for one SOP: ${existing?existing.title:'Not selected'}\nRequested SOP need: ${genNeed.value||'Not specified'}\nCompany-specific rules/exclusions: ${genRules.value||'None'}\n\nRules:\n- Generated content must be a draft for human review, not legal, HR, financial, compliance, regulated, or professional advice.\n- Do not include passwords, payment details, private customer records, regulated records, confidential files, or sensitive personal data.\n- Write practical operational steps, not marketing copy.\n- Use clear staff-friendly language.\n- Keep SOP statuses out of the JSON; the portal will assign Draft or Pending Review.\n- Use arrays for steps.\n\nReturn this JSON shape:\n{\n  \"sections\": [\n    {\"title\":\"Section name\", \"description\":\"Short section description\", \"icon\":\"Checklist\"}\n  ],\n  \"sops\": [\n    {\n      \"sectionTitle\":\"Section name or existing section name\",\n      \"title\":\"SOP title\",\n      \"purpose\":\"Why this SOP exists\",\n      \"scope\":\"Who/what this applies to\",\n      \"prerequisites\":\"Access, tools, or conditions needed first\",\n      \"steps\":[\"Step one\", \"Step two\"],\n      \"validation\":\"How staff know it is complete\",\n      \"exceptions\":\"Escalations, cautions, or exceptions\",\n      \"owner\":\"Recommended owner role\",\n      \"roles\":\"Who uses this SOP\",\n      \"tags\":\"comma separated search tags\"\n    }\n  ]\n}`;genPrompt.value=prompt;return prompt}
async function copyGeneratorPrompt(){if(!genPrompt.value)buildGeneratorPrompt();try{await navigator.clipboard.writeText(genPrompt.value);status.textContent='SOP Generator prompt copied.'}catch(e){genPrompt.focus();genPrompt.select();document.execCommand('copy');status.textContent='SOP Generator prompt copied.'}}
function extractGeneratedJson(text){let t=String(text||'').trim();t=t.replace(/^```(?:json)?/i,'').replace(/```$/,'').trim();try{return JSON.parse(t)}catch(e){}for(const pair of [['{','}'],['[',']']]){const a=t.indexOf(pair[0]),b=t.lastIndexOf(pair[1]);if(a>-1&&b>a){try{return JSON.parse(t.slice(a,b+1))}catch(e){}}}return null}
function normalizeSopRoleName(r){const v=String(r||'').trim(),key=v.toLowerCase();return key==='everyone'||key==='staff'||key==='all staff'?'All Staff':v}function normalizeSopRoles(v){const seen=new Set(),out=[];for(const r of String(v||'').split(',')){const role=normalizeSopRoleName(r);if(role&&!seen.has(role.toLowerCase())){seen.add(role.toLowerCase());out.push(role)}}return out.join(', ')||'All Staff'}
function sectionKey(v){return String(v||'').toLowerCase().replace(/[^a-z0-9]+/g,' ').trim()}
function previewSectionsFromSops(items,fallbackTitle,description){const seen=new Set(),out=[];for(const item of items||[]){const title=String(item?.sectionTitle||item?.section||item?.sectionName||'').trim();const key=sectionKey(title);if(title&&key&&!seen.has(key)){seen.add(key);out.push({title,description:description||'Generated SOP section.',icon:'Checklist'})}}return out.length?out:[{title:fallbackTitle,description:description||'Generated SOP section.',icon:'Checklist'}]}
function mergePreviewSections(sections,items,fallbackTitle,description){const seen=new Set(),out=[];function add(sec,desc){const title=String(sec?.title||sec?.name||'').trim(),key=sectionKey(title);if(title&&key&&!seen.has(key)){seen.add(key);out.push({title,description:String(sec?.description||sec?.summary||desc||description||'Generated SOP section.').trim(),icon:String(sec?.icon||'Checklist').trim()})}}for(const sec of sections||[])add(sec,description);for(const item of items||[])add({title:item?.sectionTitle,description,icon:'Checklist'},description);return out.length?out:[{title:fallbackTitle,description:description||'Generated SOP section.',icon:'Checklist'}]}
function splitLines(v){if(Array.isArray(v))return v.map(x=>String(x).trim()).filter(Boolean);return String(v||'').split(/\r?\n|(?:^|\s)\d+\.\s+/).map(x=>x.replace(/^[-*]\s*/,'').trim()).filter(Boolean)}
function generatedMarkdownFallback(text){const lines=String(text||'').split(/\r?\n/).map(x=>x.trim()).filter(Boolean),title=(lines.find(x=>/^#|^sop[:\s-]/i.test(x))||lines[0]||'Generated SOP').replace(/^#+\s*|^sop[:\s-]*/ig,'').trim();return{sections:[],sops:[{title,sectionTitle:sectionTitle(genExistingSection.value),purpose:'Review and complete this generated draft.',scope:genAudience.value||'Staff using this workflow.',prerequisites:'Review business tools, permissions, and manager instructions before use.',steps:lines.slice(1).filter(x=>!/^purpose|scope|validation|exception/i.test(x)).slice(0,30),validation:'Manager confirms the SOP is accurate before approval.',exceptions:'Escalate unclear or sensitive situations to a manager.',owner:DATA.settings.defaultOwner||'Manager',roles:genAudience.value||'Staff',tags:genVertical.value||'generated'}]}}
function normalizeGeneratedResult(raw){const obj=raw||generatedMarkdownFallback(genPaste.value),warnings=[];let sections=Array.isArray(obj)?[]:Array.isArray(obj.sections)?obj.sections:(obj.section?[obj.section]:[]);let sops=Array.isArray(obj)?obj:Array.isArray(obj.sops)?obj.sops:Array.isArray(obj.SOPs)?obj.SOPs:(obj.sop?[obj.sop]:[]);if(!sops.length&&obj.title)sops=[obj];sections=sections.map(s=>({title:String(s.title||s.name||'Generated Section').trim(),description:String(s.description||s.summary||'Generated SOP section.').trim(),icon:String(s.icon||'Checklist').trim()})).filter(s=>s.title);sops=sops.map((s,i)=>{const title=String(s.title||s.name||`Generated SOP ${i+1}`).trim();const steps=splitLines(s.steps||s.procedure||s.instructions);if(!steps.length)warnings.push(`${title}: no steps found; review before saving.`);for(const key of ['purpose','scope','validation','exceptions'])if(!String(s[key]||'').trim())warnings.push(`${title}: missing ${key}.`);return{sectionTitle:String(s.sectionTitle||s.section||s.sectionName||sections[0]?.title||sectionTitle(genExistingSection.value)||'Generated').trim(),title,purpose:String(s.purpose||'Review and complete this generated draft.').trim(),scope:String(s.scope||genAudience.value||'Staff using this workflow.').trim(),prerequisites:String(s.prerequisites||s.requirements||'Review required tools, permissions, and manager instructions before use.').trim(),steps:steps.length?steps:['Review this generated SOP draft.','Update details for the customer environment.','Submit for manager approval before staff use.'],validation:String(s.validation||s.doneState||'Manager confirms the SOP is accurate before approval.').trim(),exceptions:String(s.exceptions||s.notes||'Escalate unclear or sensitive situations to a manager.').trim(),owner:String(s.owner||DATA.settings.defaultOwner||'Manager').trim(),roles:normalizeSopRoles(s.roles||genAudience.value||'Staff'),tags:String(s.tags||genVertical.value||'generated').trim()}});if(genMode.value!=='one')sections=mergePreviewSections(sections,sops,genSectionName.value.trim()||'Generated Section','Generated SOP section.');if(!sops.length)warnings.push('No SOPs were found in the pasted result.');if(genMode.value!=='one'&&!MANAGER_ROLES.includes(ME.role))warnings.push('Only Manager or Admin can save generated sections or seed portal content.');return{sections,sops,warnings}}
function parseGeneratorResult(){const raw=extractGeneratedJson(genPaste.value)||generatedMarkdownFallback(genPaste.value);GEN_PREVIEW=normalizeGeneratedResult(raw);renderGeneratorPreview()}
