function renderUsers(){if(ME?.role!=='Admin')return;userList.innerHTML=USERS.map(u=>`<div class="user-row ${u.username===selectedUsername?'active':''}" onclick="selectUser('${escAttr(u.username)}')"><b>${esc(u.username)}</b> <span class="pill">${esc(u.role)}</span><div class="small">${esc(u.displayName)} · ${u.active?'Active':'Disabled'}</div></div>`).join('')}function selectUser(username){selectedUsername=username;const u=USERS.find(x=>x.username===username);if(!u)return;user_username.value=u.username;user_displayName.value=u.displayName;user_role.value=u.role;user_active.value=String(u.active!==false);user_password.value='';renderUsers()}function clearUser(){selectedUsername=null;user_username.value='';user_displayName.value='';user_role.value='Staff';user_active.value='true';user_password.value='';renderUsers()}async function createUser(){const payload={username:user_username.value,displayName:user_displayName.value,role:user_role.value,active:user_active.value==='true',password:user_password.value};const r=await fetch('/api/users',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)});const d=await r.json().catch(()=>({}));if(!r.ok)return alert(d.error||'Create failed');USERS=d.users;selectedUsername=payload.username;user_password.value='';renderUsers();renderDashboard()}async function updateUser(){if(!selectedUsername)return alert('Select a user first.');const p={username:selectedUsername,displayName:user_displayName.value,role:user_role.value,active:user_active.value==='true'};if(user_password.value)p.password=user_password.value;const r=await fetch('/api/users',{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify(p)});const d=await r.json().catch(()=>({}));if(!r.ok)return alert(d.error||'Update failed');USERS=d.users;user_password.value='';renderUsers();renderDashboard()}async function deleteUser(){if(!selectedUsername)return alert('Select a user first.');if(!confirm('Delete this user?'))return;const r=await fetch('/api/users?username='+encodeURIComponent(selectedUsername),{method:'DELETE'});const d=await r.json().catch(()=>({}));if(!r.ok)return alert(d.error||'Delete failed');USERS=d.users;clearUser();renderDashboard()}
function syncJson(){if(DATA)jsonArea.value=JSON.stringify(DATA,null,2)}function applyJson(){if(ME.role!=='Admin')return alert('Admin role required.');try{const next=JSON.parse(jsonArea.value);if(!next.brand||!Array.isArray(next.sections)||!Array.isArray(next.sops))throw new Error('JSON must include brand, sections, and sops.');if(!next._dataVersion&&SAVED_DATA?._dataVersion)next._dataVersion=SAVED_DATA._dataVersion;DATA=next;currentSopId=DATA.sops[0]?.id;currentSectionId=DATA.sections[0]?.id;fillBrand();renderAll()}catch(e){alert(e.message||'Invalid JSON')}}async function publish(){if(saveSop(false)===false)return false;saveSectionForm();if(ME.role==='Admin')collectBrand();if(!DATA._dataVersion&&SAVED_DATA?._dataVersion)DATA._dataVersion=SAVED_DATA._dataVersion;const saveVersion=DATA._dataVersion||'';const r=await fetch('/api/sops',{method:'PUT',headers:{'Content-Type':'application/json','If-Match':saveVersion},body:JSON.stringify(DATA)});const d=await r.json().catch(()=>({}));if(!r.ok){if(r.status===409){status.textContent='Save blocked because live SOP data changed. Reload from server, review the newer data, then apply your edits again.';alert(d.error||'SOP data changed since this page loaded. Reload before saving.')}else alert(d.error||'Publish failed');return false}if(d.dataVersion)DATA._dataVersion=d.dataVersion;let portChanged=false,linkChanged=false;if(ME.role==='Admin'&&byId('config_port')){const nextPort=Number(config_port.value)||8086,rawBase=byId('config_mobileBaseUrl')?config_mobileBaseUrl.value.trim():PORTAL.mobileBaseUrl||'',nextBase=cleanMobileBaseUrl(rawBase);if(rawBase&&!nextBase){alert('Mobile / QR Base URL must look like http://192.168.4.25:8086. Use a colon before the port number.');return false}if(rawBase&&nextBase!==rawBase.replace(/\/+$/,''))config_mobileBaseUrl.value=nextBase;if(nextPort!==Number(PORTAL.port||8086)||nextBase!==String(PORTAL.mobileBaseUrl||'')){const pr=await fetch('/api/portal-settings',{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({port:nextPort,mobileBaseUrl:nextBase})});const pd=await pr.json().catch(()=>({}));if(!pr.ok){alert(pd.error||'Portal settings update failed');return false}portChanged=nextPort!==Number(PORTAL.port||8086);linkChanged=nextBase!==String(PORTAL.mobileBaseUrl||'');PORTAL=pd.settings;fillBrand()}}SAVED_DATA=JSON.parse(JSON.stringify(DATA));status.textContent='Saved at '+new Date().toLocaleString()+'. Backup created.'+(portChanged?' Restart the portal for the new port to take effect.':'')+(linkChanged?' QR and copied SOP links now use the mobile base URL.':'');renderDashboard();return true}function exportJson(){const blob=new Blob([JSON.stringify(DATA,null,2)],{type:'application/json'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download='sop-portal-sops.json';a.click();URL.revokeObjectURL(url)}function importJson(file){if(ME.role!=='Admin')return alert('Admin role required.');const r=new FileReader();r.onload=()=>{try{const next=JSON.parse(r.result);if(!next.brand||!Array.isArray(next.sections)||!Array.isArray(next.sops))throw new Error('JSON must include brand, sections, and sops.');if(!next._dataVersion&&SAVED_DATA?._dataVersion)next._dataVersion=SAVED_DATA._dataVersion;DATA=next;currentSopId=DATA.sops[0]?.id;currentSectionId=DATA.sections[0]?.id;fillBrand();renderAll();syncJson()}catch(e){alert(e.message||'Invalid JSON import')}};r.readAsText(file)}
function setTab(tab){if((tab==='users'||tab==='brand'||tab==='json'||tab==='support')&&ME.role!=='Admin')return alert('Admin role required.');if(tab==='sections'&&!MANAGER_ROLES.includes(ME.role))return alert('Manager/Admin required.');document.querySelectorAll('.tab').forEach(x=>x.classList.add('hidden'));byId('tab-'+tab).classList.remove('hidden');document.querySelectorAll('.admin-nav button').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));if(tab==='json'){saveSop(false);saveSectionForm();collectBrand();syncJson()}if(tab==='dashboard')renderDashboard();if(tab==='generator')renderGenerator();if(tab==='import')renderImport();if(tab==='requests')renderRequests();if(tab==='support')renderSupports();if(tab==='users'){renderUsers();renderPortalSettings();renderSecurityOptions()}if(tab==='sections'){renderSectionList();renderSectionForm()}}
function sectionTitle(id){return DATA.sections.find(s=>s.id===id)?.title||id}function statusClass(s){return String(s||'').toLowerCase().replace(/\s+/g,'-')}function incrementVersion(v){const n=String(v||'0.0').match(/^(\d+)(?:\.(\d+))?/);return n?`${n[1]}.${Number(n[2]||0)+1}`:'1.0'}function fileToDataUrl(file){return new Promise((resolve,reject)=>{const reader=new FileReader();reader.onload=()=>resolve(reader.result);reader.onerror=()=>reject(reader.error);reader.readAsDataURL(file)})}function isImage(a){return String(a.type||'').startsWith('image/')||/\.(png|jpe?g|gif|webp|avif|svg)$/i.test(a.name||a.url||'')}function formatBytes(bytes){const n=Number(bytes)||0;if(n<1024)return n+' B';if(n<1048576)return(n/1024).toFixed(1)+' KB';return(n/1048576).toFixed(1)+' MB'}function norm(s){return String(s||'').toLowerCase()}function esc(s){return String(s||'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]))}function escAttr(s){return esc(s).replace(/`/g,'&#096;')}function byId(id){return document.getElementById(id)}async function logout(){await fetch('/api/logout',{method:'POST'});location.href='/login.html'}
logoutBtn.onclick=logout;deniedLogoutBtn.onclick=logout;publishBtn.onclick=publish;reloadBtn.onclick=loadData;exportBtn.onclick=exportJson;importBtn.onclick=()=>importFile.click();importFile.onchange=e=>e.target.files[0]&&importJson(e.target.files[0]);addSopBtn.onclick=addSop;dupSopBtn.onclick=duplicateSop;deleteSopBtn.onclick=deleteSop;addSectionBtn.onclick=addSection;deleteSectionBtn.onclick=deleteSection;adminSearch.oninput=renderSopList;if(byId('adminSectionFilter'))adminSectionFilter.onchange=renderSopList;if(byId('adminStatusFilter'))adminStatusFilter.onchange=renderSopList;uploadAttachmentsBtn.onclick=uploadAttachments;saveDraftBtn.onclick=async()=>{if(saveSop(false)===false)return;const desired=sop_status.value||'Draft';makeDraftCopyIfNeeded(desired);sop_status.value=desired;if(saveSop(true,'Saved')!==false)await publish()};submitReviewBtn.onclick=async()=>{if(saveSop(false)===false)return;makeDraftCopyIfNeeded('Pending Review');sop_status.value='Pending Review';if(saveSop(true,'Submitted for Review')!==false)await publish()};approveBtn.onclick=()=>setStatus('Approved','Approved');rejectBtn.onclick=()=>setStatus('Rejected','Rejected');archiveBtn.onclick=()=>setStatus('Archived','Archived');rollbackBtn.onclick=rollbackVersion;requestFilter.onchange=renderRequests;toggleStaffLoginBtn.onclick=toggleStaffLogin;if(byId('saveStaffPortalAccessBtn'))saveStaffPortalAccessBtn.onclick=saveStaffPortalAccess;if(byId('buildGenPromptBtn'))buildGenPromptBtn.onclick=buildGeneratorPrompt;if(byId('copyGenPromptBtn'))copyGenPromptBtn.onclick=copyGeneratorPrompt;if(byId('parseGenResultBtn'))parseGenResultBtn.onclick=parseGeneratorResult;if(byId('clearGenResultBtn'))clearGenResultBtn.onclick=clearGenerator;if(byId('saveGenDraftBtn'))saveGenDraftBtn.onclick=()=>saveGenerated('Draft');if(byId('saveGenReviewBtn'))saveGenReviewBtn.onclick=()=>saveGenerated('Pending Review');if(byId('genMode'))genMode.onchange=renderGenerator;if(byId('buildImportPromptBtn'))buildImportPromptBtn.onclick=buildImportPrompt;if(byId('copyImportPromptBtn'))copyImportPromptBtn.onclick=copyImportPrompt;if(byId('parseImportResultBtn'))parseImportResultBtn.onclick=parseImportResult;if(byId('clearImportResultBtn'))clearImportResultBtn.onclick=clearImport;if(byId('saveImportDraftBtn'))saveImportDraftBtn.onclick=()=>saveImported('Draft');if(byId('saveImportReviewBtn'))saveImportReviewBtn.onclick=()=>saveImported('Pending Review');if(byId('importMode'))importMode.onchange=renderImport;if(byId('saveSecurityOptionsBtn'))saveSecurityOptionsBtn.onclick=saveSecurityOptions;if(byId('runSmokeTestBtn'))runSmokeTestBtn.onclick=runSmokeTest;if(byId('uploadBrandLogoBtn'))uploadBrandLogoBtn.onclick=uploadBrandLogo;if(byId('resetBrandLogoBtn'))resetBrandLogoBtn.onclick=resetBrandLogo;if(byId('revertLastColorsBtn'))revertLastColorsBtn.onclick=()=>brandColorAction('revert-previous');if(byId('restoreDefaultColorsBtn'))restoreDefaultColorsBtn.onclick=()=>brandColorAction('restore-default');if(byId('saveDefaultColorsBtn'))saveDefaultColorsBtn.onclick=()=>brandColorAction('save-default');createUserBtn.onclick=createUser;updateUserBtn.onclick=updateUser;deleteUserBtn.onclick=deleteUser;clearUserBtn.onclick=clearUser;document.querySelectorAll('.admin-nav button').forEach(b=>b.onclick=()=>setTab(b.dataset.tab));document.querySelectorAll('#sopForm input,#sopForm textarea,#sopForm select').forEach(el=>el.addEventListener('input',()=>saveSop(false)));document.querySelectorAll('#tab-sections input,#tab-sections textarea').forEach(el=>el.addEventListener('input',()=>{saveSectionForm();renderSectionList()}));document.querySelectorAll('#tab-brand input,#tab-brand textarea').forEach(el=>el.addEventListener('input',collectBrand));jsonArea.addEventListener('change',applyJson);window.selectSop=selectSop;window.editSop=editSop;window.deleteAttachment=deleteAttachment;window.selectVersion=selectVersion;window.selectRequest=selectRequest;window.updateRequest=updateRequest;window.selectSupport=selectSupport;window.selectUser=selectUser;window.selectSection=selectSection;window.moveSection=moveSection;window.moveSopInSection=moveSopInSection;window.selectGeneratorHistory=selectGeneratorHistory;boot();
